-- =====================================================================
-- TMGD YÖNETİM SİSTEMİ — MIGRATION 009 (v3 — TAM 2939 SATIR)
-- TAM ADR UN NUMARALARI VERİTABANI (ADR_A_TABLOSU.xlsx kaynaklı)
-- =====================================================================
-- NEDEN 2939 SATIR:
-- ADR'de aynı UN numarası birden fazla satırda yer alır (örn. UN 1950
-- Aerosol: 5A/5C/5F/5T/5FC/5TF vb. her biri farklı sınıflandırma kodu,
-- etiket ve taşıma kategorisi taşır). Bu farklar ADR uyum açısından
-- kritiktir — hepsi ayrı kayıt olarak korunur.
-- ÇÖZÜM: un_number UNIQUE constraint kaldırıldı; her satır kendi
-- UUID id'siyle tutulur. Arama: un_number = 'XXXX' birden fazla satır döner.
-- KULLANIM: Supabase SQL Editor → tamamını yapıştır → RUN
-- =====================================================================

ALTER TABLE public.adr_un_numbers
    DROP CONSTRAINT IF EXISTS adr_un_numbers_un_number_key;

CREATE TABLE IF NOT EXISTS public.adr_un_numbers (
    id                   uuid PRIMARY KEY DEFAULT gen_random_uuid(),
    un_number            varchar(10)  NOT NULL,
    proper_shipping_name text         NOT NULL,
    class                text,
    classification_code  text,
    packing_group        text,
    tunnel_code          text,
    hazard_no            text,
    labels               text,
    transport_category   text,
    limited_quantity     text,
    excepted_quantity    text,
    special_provisions   text,
    packing_instruction  text,
    created_at           timestamptz  DEFAULT now()
);

ALTER TABLE public.adr_un_numbers
    ADD COLUMN IF NOT EXISTS special_provisions  text,
    ADD COLUMN IF NOT EXISTS packing_instruction text;

ALTER TABLE public.adr_un_numbers ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS adr_un_select ON public.adr_un_numbers;
CREATE POLICY adr_un_select ON public.adr_un_numbers FOR SELECT USING (true);
DROP POLICY IF EXISTS adr_un_write  ON public.adr_un_numbers;
CREATE POLICY adr_un_write  ON public.adr_un_numbers FOR ALL   USING (public.is_admin());

ALTER TABLE public.adr_synonyms ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS adr_syn_select ON public.adr_synonyms;
CREATE POLICY adr_syn_select ON public.adr_synonyms FOR SELECT USING (true);

-- Mevcut kayıtları temizle (tam yeniden yükle — idempotent)
TRUNCATE public.adr_un_numbers RESTART IDENTITY CASCADE;

